input.command:
powershell -File - <<'PS1'
$files = Get-ChildItem -Path 'C:\Users\25789' -Recurse -File -ErrorAction SilentlyContinue | Where-Object { $_.Length -gt 1MB } | Group-Object -Property Length, Name | Where-Object { $_.Count -gt 1 }
$files | Sort-Object Count -Descending | Select-Object -First 15 | ForEach-Object {
    $g = $_
    $sizeKB = [math]::Round($g.Group[0].Length / 1KB, 0)
    Write-Host ("[重复 " + $g.Count + " 份] " + $sizeKB + "KB " + $g.Group[0].Name)
    $g.Group.FullName | ForEach-Object { Write-Host ("  " + $_) }
}
